import "core-js/modules/es.iterator.constructor.js";
import "core-js/modules/es.iterator.for-each.js";
import "core-js/modules/es.iterator.map.js";
import "core-js/modules/es.iterator.reduce.js";
import "core-js/modules/es.json.stringify.js";
import "core-js/modules/es.set.difference.v2.js";
import "core-js/modules/es.set.intersection.v2.js";
import "core-js/modules/es.set.is-disjoint-from.v2.js";
import "core-js/modules/es.set.is-subset-of.v2.js";
import "core-js/modules/es.set.is-superset-of.v2.js";
import "core-js/modules/es.set.symmetric-difference.v2.js";
import "core-js/modules/es.set.union.v2.js";
import "core-js/modules/esnext.json.parse.js";
import "core-js/modules/web.url-search-params.delete.js";
import "core-js/modules/web.url-search-params.has.js";
import "core-js/modules/web.url-search-params.size.js";
import { ref, computed, onMounted } from 'vue';
import { useStore } from 'vuex';
import api, { connectSocket } from '@/api';
import { ElMessage } from 'element-plus';
import { DataAnalysis, Refresh, Star, Picture as PictureIcon, Document, Upload, Connection, Odometer } from '@element-plus/icons-vue';
export default {
  name: 'Cluster',
  components: {
    DataAnalysis,
    Refresh,
    Star,
    PictureIcon,
    Document,
    Upload,
    Connection,
    Odometer
  },
  setup() {
    const store = useStore();
    const files = computed(() => store.state.files);
    const selectedFiles = ref([]);
    const loading = ref(false);
    const options = ref({
      nClusters: 5,
      method: 'kmeans',
      language: 'chinese'
    });
    const clustering = ref(false);
    const result = ref(null);
    const activeClusters = ref(['0', '1', '2']);
    const showVisualization = ref(false);
    const vizCanvas = ref(null);

    // 向量聚相关
    const clusterMode = ref('traditional');
    const vectorOptions = ref({
      nClusters: 5
    });
    const vectorClustering = ref(false);
    const syncing = ref(false);
    const vectorStats = ref({
      total_papers: 0,
      dimension: 0,
      connected: false,
      collection_name: ''
    });
    const paperTable = ref(null);
    const syncedPaperIds = ref(new Set());

    // 测试相关
    const testingConnection = ref(false);
    const testingCluster = ref(false);
    const showTestResult = ref(false);
    const testResult = ref(null);

    // 当前聚类结果ID
    const currentResultId = ref(null);

    // 聚类历史记录
    const clusterHistory = ref([]);

    // 从localStorage加载历史记录
    const loadHistory = () => {
      try {
        const saved = localStorage.getItem('cluster_history');
        if (saved) {
          clusterHistory.value = JSON.parse(saved);
        }
      } catch (e) {
        console.error('加载历史记录失败:', e);
      }
    };

    // 保存历史记录到localStorage
    const saveHistory = () => {
      try {
        localStorage.setItem('cluster_history', JSON.stringify(clusterHistory.value));
      } catch (e) {
        console.error('保存历史记录失败:', e);
      }
    };

    // 格式化日期
    const formatDate = dateStr => {
      if (!dateStr) return '';
      const date = new Date(dateStr);
      return date.toLocaleString('zh-CN');
    };

    // 加载历史结果
    const loadHistoryResult = historyItem => {
      result.value = historyItem.data;
      currentResultId.value = null; // 历史结果不需要再保存
      activeClusters.value = Object.keys(historyItem.data.clusterAnalysis).slice(0, 3);
      ElMessage.success('已加载历史聚类结果');
    };

    // 删除历史结果
    const deleteHistoryResult = index => {
      clusterHistory.value.splice(index, 1);
      saveHistory();
      ElMessage.success('已删除');
    };

    // 清空历史
    const clearHistory = () => {
      clusterHistory.value = [];
      saveHistory();
      ElMessage.success('历史记录已清空');
    };

    // 保存当前结果
    const saveCurrentResult = () => {
      if (!result.value) return;

      // 计算论文总数 - 从聚类分析中统计
      let paperCount = 0;
      if (result.value.papers && result.value.papers.length > 0) {
        // 传统聚类方式
        paperCount = result.value.papers.length;
      } else if (result.value.clusterAnalysis) {
        // 向量聚类方式 - 从各个聚类中统计论文数
        Object.values(result.value.clusterAnalysis).forEach(cluster => {
          paperCount += cluster.paper_count || 0;
        });
      }
      const historyItem = {
        id: Date.now().toString(),
        createdAt: new Date().toISOString(),
        clusterCount: result.value.clusterCount,
        method: result.value.method,
        paperCount: paperCount,
        data: result.value
      };
      clusterHistory.value.unshift(historyItem);
      saveHistory();
      currentResultId.value = null; // 已保存，不需要再显示保存按钮
      ElMessage.success('聚类结果已保存到历史记录');
    };

    // 检查论文是否在向量库中
    const isPaperInVectorStore = paperId => {
      return syncedPaperIds.value.has(paperId);
    };

    // 向量聚类方法
    const loadVectorStats = async () => {
      try {
        const response = await api.getVectorStoreStats();
        if (response.success) {
          vectorStats.value = response.data;
        }
      } catch (error) {
        console.error('加载向量统计失败:', error);
      }
    };

    // 加载已同步的论文ID列表
    const loadSyncedPaperIds = async () => {
      try {
        // 通过搜索空字符串来获取所有论文ID
        const response = await api.searchVectorStore('', 1000);
        if (response.success && response.data) {
          syncedPaperIds.value = new Set(response.data.map(p => p.paper_id));
          console.log(`[DEBUG] 已加载 ${syncedPaperIds.value.size} 个已同步论文ID`);
        }
      } catch (error) {
        console.error('加载已同步论文列表失败:', error);
      }
    };

    // 测试向量连接
    const testVectorConnection = async () => {
      testingConnection.value = true;
      try {
        const response = await api.getVectorStoreStats();
        if (response.success) {
          vectorStats.value = response.data;
          ElMessage.success(`向量库连接正常，包含 ${response.data?.total_papers || 0} 篇论文`);
        } else {
          ElMessage.error('向量库连接失败: ' + (response.error || '未知错误'));
        }
      } catch (error) {
        console.error('测试连接失败:', error);
        ElMessage.error('向量库连接测试失败: ' + (error.message || '请检查Milvus服务'));
      } finally {
        testingConnection.value = false;
      }
    };

    // 测试向量聚类
    const testVectorCluster = async () => {
      testingCluster.value = true;
      testResult.value = null;
      try {
        // 1. 首先检查向量库状态
        const statsResponse = await api.getVectorStoreStats();
        if (!statsResponse.success) {
          testResult.value = {
            success: false,
            connected: false,
            error: '无法连接到向量库: ' + (statsResponse.error || '未知错误')
          };
          showTestResult.value = true;
          return;
        }
        const stats = statsResponse.data;
        if (stats.total_papers < 2) {
          testResult.value = {
            success: false,
            connected: true,
            collection_name: stats.collection_name,
            dimension: stats.dimension,
            total_papers: stats.total_papers,
            error: '向量库中论文数量不足，无法进行聚类测试。请先同步论文到向量库。'
          };
          showTestResult.value = true;
          return;
        }

        // 2. 尝试进行聚类测试
        const testClusterCount = Math.min(3, stats.total_papers);
        ElMessage.info(`正在进行聚类测试，使用 ${stats.total_papers} 篇论文...`);
        const clusterResponse = await api.clusterPapersVector(testClusterCount);
        if (clusterResponse.success) {
          testResult.value = {
            success: true,
            connected: true,
            collection_name: stats.collection_name,
            dimension: stats.dimension,
            total_papers: stats.total_papers,
            available_papers: clusterResponse.data?.total_papers || stats.total_papers,
            test_cluster: clusterResponse.data || {},
            message: '向量聚类测试成功！向量库工作正常。'
          };
          ElMessage.success('向量聚类测试成功');
        } else {
          testResult.value = {
            success: false,
            connected: true,
            collection_name: stats.collection_name,
            dimension: stats.dimension,
            total_papers: stats.total_papers,
            error: '聚类测试失败: ' + (clusterResponse.error || '未知错误')
          };
        }
      } catch (error) {
        console.error('聚类测试失败:', error);
        testResult.value = {
          success: false,
          connected: false,
          error: '聚类测试异常: ' + (error.message || '请检查Milvus服务是否正常运行')
        };
      } finally {
        testingCluster.value = false;
        showTestResult.value = true;
      }
    };
    const syncToVectorStore = async () => {
      if (selectedFiles.value.length === 0) {
        ElMessage.warning('请先选择要同步的论文');
        return;
      }
      syncing.value = true;
      try {
        const paperIds = selectedFiles.value.map(f => f.id);
        const response = await api.syncPapersToVectorStore(paperIds);
        if (response.success) {
          ElMessage.success(`同步完成: ${response.data?.synced || 0} 成功, ${response.data?.failed || 0} 失败`);
          // 更新已同步论文集合
          paperIds.forEach(id => syncedPaperIds.value.add(id));
          await loadVectorStats();
        } else {
          ElMessage.error(response.error || '同步失败');
        }
      } catch (error) {
        console.error('同步失败:', error);
        ElMessage.error('同步到向量库失败');
      } finally {
        syncing.value = false;
      }
    };
    const startVectorCluster = async () => {
      if (selectedFiles.value.length < 2) {
        ElMessage.warning('请至少选择2篇论文');
        return;
      }
      vectorClustering.value = true;
      try {
        const paperIds = selectedFiles.value.map(f => f.id);
        const response = await api.clusterPapersVector(vectorOptions.value.nClusters, paperIds);
        if (response.success) {
          console.log('[DEBUG] 向量聚类响应:', response);
          console.log('[DEBUG] cluster_analysis:', response.data?.cluster_analysis);
          result.value = {
            clusterCount: response.data?.n_clusters || 0,
            clusterAnalysis: response.data?.cluster_analysis || {},
            papers: [],
            method: 'kmeans_vector',
            createdAt: new Date().toISOString(),
            inertia: response.data?.inertia || 0
          };
          currentResultId.value = Date.now().toString();
          ElMessage.success(`向量聚类完成! 共发现 ${response.data?.n_clusters || 0} 个主题类别`);
          const clusterIds = Object.keys(response.data?.cluster_analysis || {});
          activeClusters.value = clusterIds.slice(0, 3);
          saveCurrentResult();
        } else {
          ElMessage.error(response.error || '向量聚类失败');
        }
      } catch (error) {
        console.error('[ERROR] 向量聚类错误:', error);
        ElMessage.error('向量聚类失败: ' + (error.response?.data?.error || error.message));
      } finally {
        vectorClustering.value = false;
      }
    };
    const handleSelectionChange = selection => {
      selectedFiles.value = selection;
    };
    const refreshFiles = async () => {
      loading.value = true;
      try {
        await store.dispatch('fetchFiles');
        ElMessage.success('论文列表已刷新');
      } catch (error) {
        console.error('刷新失败:', error);
        ElMessage.error('刷新失败');
      } finally {
        loading.value = false;
      }
    };
    const startCluster = async () => {
      if (selectedFiles.value.length < 2) {
        ElMessage.warning('请至少选择2篇论文');
        return;
      }

      // 验证聚类数量
      const maxClusters = Math.min(20, selectedFiles.value.length);
      if (options.value.method !== 'dbscan' && (options.value.nClusters < 2 || options.value.nClusters > maxClusters)) {
        ElMessage.warning(`聚类数量必须在 2 到 ${maxClusters} 之间`);
        return;
      }

      // 连接WebSocket
      connectSocket();
      store.commit('SHOW_PROGRESS_DIALOG', true);
      store.commit('SET_PROGRESS', {
        progress: 0,
        message: '开始聚类分析...',
        step: ''
      });
      clustering.value = true;
      try {
        // 使用论文ID而不是文件路径
        const paperIds = selectedFiles.value.map(f => f.id);
        console.log('[DEBUG] 开始聚类, paper_ids:', paperIds);
        console.log('[DEBUG] 聚类选项:', options.value);
        const response = await api.clusterPapers(paperIds, options.value.nClusters, options.value.method, options.value.language);
        console.log('[DEBUG] 聚类响应:', response);
        if (response.success) {
          // 格式化结果
          result.value = {
            clusterCount: response.data?.n_clusters || 0,
            clusterAnalysis: response.data?.cluster_analysis || {},
            papers: response.data?.papers || [],
            method: options.value.method,
            createdAt: new Date().toISOString()
          };

          // 生成新的结果ID
          currentResultId.value = Date.now().toString();
          store.commit('SET_PROGRESS', {
            progress: 100,
            message: '聚类完成!'
          });
          ElMessage.success(`聚类分析完成! 共发现 ${response.data?.n_clusters || 0} 个主题类别`);

          // 自动展开前3个聚类
          const clusterIds = Object.keys(response.data?.cluster_analysis || {});
          activeClusters.value = clusterIds.slice(0, 3);

          // 自动保存到历史记录
          saveCurrentResult();
        } else {
          ElMessage.error({
            message: response.error || '聚类失败',
            duration: 5000,
            showClose: true
          });
        }
      } catch (error) {
        console.error('[ERROR] 聚类错误:', error);

        // 提供更详细的错误提示
        let errorMsg = '聚类失败';
        const errorDetail = error.response?.data?.error || error.message;
        if (errorDetail) {
          if (errorDetail.includes('论文') || errorDetail.includes('PDF')) {
            errorMsg = '论文加载或解析失败，请检查文件是否完整';
          } else if (errorDetail.includes('聚类') || errorDetail.includes('算法')) {
            errorMsg = '聚类算法执行失败，请尝试调整参数';
          } else if (errorDetail.includes('数量') || errorDetail.includes('不足')) {
            errorMsg = '可用论文数量不足，无法进行聚类';
          } else if (errorDetail.includes('timeout') || errorDetail.includes('超时')) {
            errorMsg = '聚类超时，请减少论文数量或降低聚类数量';
          } else {
            errorMsg = `聚类失败: ${errorDetail}`;
          }
        } else if (error.message) {
          errorMsg = `聚类失败: ${error.message}`;
        }
        ElMessage.error({
          message: errorMsg,
          duration: 5000,
          showClose: true
        });
      } finally {
        clustering.value = false;
        store.commit('SHOW_PROGRESS_DIALOG', false);
      }
    };
    const downloadVisualization = () => {
      showVisualization.value = true;
      // 在对话框打开后绘制可视化
      setTimeout(() => {
        drawVisualization();
      }, 100);
    };
    const drawVisualization = () => {
      const canvas = vizCanvas.value;
      if (!canvas) return;

      // 设置高分辨率画布
      const dpr = window.devicePixelRatio || 1;
      const width = window.innerWidth * 0.85;
      const height = window.innerHeight * 0.75;
      canvas.width = width * dpr;
      canvas.height = height * dpr;
      canvas.style.width = width + 'px';
      canvas.style.height = height + 'px';
      const ctx = canvas.getContext('2d');
      ctx.scale(dpr, dpr);

      // 背景
      ctx.fillStyle = '#f8f9fa';
      ctx.fillRect(0, 0, width, height);

      // 标题
      ctx.fillStyle = '#333';
      ctx.font = 'bold 28px Arial';
      ctx.textAlign = 'center';
      ctx.fillText('论文主题聚类可视化', width / 2, 50);
      if (!result.value || !result.value.clusterAnalysis) {
        return;
      }

      // 绘制聚类圆形图
      const clusters = Object.entries(result.value.clusterAnalysis);
      const colors = ['#FF6B6B', '#4ECDC4', '#45B7D1', '#FFA07A', '#98D8C8', '#F7DC6F', '#BB8FCE', '#85C1E2', '#F8B500', '#6C5CE7'];
      const centerX = width / 2;
      const centerY = height / 2 + 30;
      const maxRadius = Math.min(width, height) * 0.35;

      // 计算总论文数
      const totalPapers = clusters.reduce((sum, [, info]) => sum + (info.paper_count || 0), 0);

      // 绘制聚类圆圈
      let currentAngle = 0;
      clusters.forEach(([clusterId, info], index) => {
        const color = colors[index % colors.length];
        const ratio = (info.paper_count || 0) / Math.max(totalPapers, 1);
        const angle = ratio * Math.PI * 2;

        // 绘制扇形
        ctx.beginPath();
        ctx.moveTo(centerX, centerY);
        ctx.arc(centerX, centerY, maxRadius, currentAngle, currentAngle + angle);
        ctx.closePath();
        ctx.fillStyle = color + '40'; // 添加透明度
        ctx.fill();
        ctx.strokeStyle = color;
        ctx.lineWidth = 3;
        ctx.stroke();

        // 绘制标签
        const labelAngle = currentAngle + angle / 2;
        const labelRadius = maxRadius + 40;
        const labelX = centerX + Math.cos(labelAngle) * labelRadius;
        const labelY = centerY + Math.sin(labelAngle) * labelRadius;
        ctx.fillStyle = color;
        ctx.font = 'bold 16px Arial';
        ctx.textAlign = 'center';
        ctx.fillText(`聚类 ${parseInt(clusterId) + 1}`, labelX, labelY - 10);
        ctx.font = '14px Arial';
        ctx.fillStyle = '#666';
        ctx.fillText(`${info.paper_count || 0}篇`, labelX, labelY + 10);
        currentAngle += angle;
      });

      // 中心圆
      ctx.beginPath();
      ctx.arc(centerX, centerY, maxRadius * 0.3, 0, Math.PI * 2);
      ctx.fillStyle = 'white';
      ctx.fill();
      ctx.strokeStyle = '#ddd';
      ctx.lineWidth = 2;
      ctx.stroke();

      // 中心文字
      ctx.fillStyle = '#333';
      ctx.font = 'bold 20px Arial';
      ctx.textAlign = 'center';
      ctx.fillText(`${clusters.length}`, centerX, centerY - 5);
      ctx.font = '14px Arial';
      ctx.fillStyle = '#666';
      ctx.fillText('个聚类', centerX, centerY + 15);

      // 绘制图例
      let legendY = height - 100;
      const legendX = width / 2 - clusters.length * 150 / 2;
      clusters.forEach(([clusterId, info], index) => {
        const color = colors[index % colors.length];
        const x = legendX + index % 5 * 150;
        const y = legendY + Math.floor(index / 5) * 40;
        ctx.fillStyle = color;
        ctx.fillRect(x, y, 20, 20);
        ctx.fillStyle = '#333';
        ctx.font = '12px Arial';
        ctx.textAlign = 'left';
        const keywords = info.top_keywords?.slice(0, 2).join(', ') || '无关键词';
        ctx.fillText(`聚类${parseInt(clusterId) + 1}: ${keywords}`, x + 30, y + 15);
      });
    };
    const downloadHighResVisualization = () => {
      const canvas = vizCanvas.value;
      if (!canvas) return;

      // 创建高分辨率下载
      const link = document.createElement('a');
      link.download = `cluster_visualization_${Date.now()}_highres.png`;
      link.href = canvas.toDataURL('image/png', 1.0);
      link.click();
      ElMessage.success('高清可视化图下载成功');
    };
    const downloadReport = async () => {
      if (!result.value) {
        ElMessage.warning('没有可导出的聚类结果');
        return;
      }
      try {
        // 生成报告内容
        let content = '论文主题聚类分析报告\n';
        content += '='.repeat(80) + '\n\n';
        content += `生成时间: ${formatDate(result.value.createdAt)}\n`;
        content += `聚类方法: ${result.value.method || 'K-Means'}\n`;
        content += `聚类数量: ${result.value.clusterCount}\n`;
        content += `论文总数: ${result.value.papers?.length || 0}\n\n`;

        // 每个聚类的详细信息
        Object.entries(result.value.clusterAnalysis).forEach(([clusterId, info]) => {
          content += `\n${'='.repeat(80)}\n`;
          content += `聚类 ${parseInt(clusterId) + 1}\n`;
          content += `${'-'.repeat(40)}\n`;
          content += `论文数: ${info.paper_count || 0}\n`;
          content += `关键词: ${info.top_keywords?.join(', ') || '无'}\n\n`;
          if (info.papers && info.papers.length > 0) {
            content += '包含论文:\n';
            info.papers.forEach((paper, i) => {
              content += `  ${i + 1}. ${paper}\n`;
            });
          }
          if (info.representative_papers && info.representative_papers.length > 0) {
            content += '\n代表性论文:\n';
            info.representative_papers.forEach((paper, i) => {
              content += `  ${i + 1}. ${paper.title || '无标题'}\n`;
              if (paper.abstract) {
                content += `     摘要: ${paper.abstract}\n`;
              }
            });
          }
        });
        content += `\n${'='.repeat(80)}\n`;
        content += '报告结束\n';

        // 下载文件
        const blob = new Blob([content], {
          type: 'text/markdown;charset=utf-8'
        });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `cluster_report_${Date.now()}.md`;
        a.click();
        URL.revokeObjectURL(url);
        ElMessage.success('聚类报告下载成功');
      } catch (error) {
        console.error('[ERROR] 导出报告失败:', error);
        ElMessage.error('导出报告失败');
      }
    };
    onMounted(() => {
      store.dispatch('fetchFiles');
      loadHistory();
      loadVectorStats();
      loadSyncedPaperIds();
    });
    return {
      files,
      selectedFiles,
      loading,
      options,
      clustering,
      result,
      activeClusters,
      currentResultId,
      clusterHistory,
      showVisualization,
      vizCanvas,
      clusterMode,
      vectorOptions,
      vectorClustering,
      syncing,
      vectorStats,
      testingConnection,
      testingCluster,
      showTestResult,
      testResult,
      paperTable,
      handleSelectionChange,
      refreshFiles,
      formatDate,
      startCluster,
      downloadVisualization,
      drawVisualization,
      downloadHighResVisualization,
      downloadReport,
      saveCurrentResult,
      loadHistoryResult,
      deleteHistoryResult,
      clearHistory,
      syncToVectorStore,
      startVectorCluster,
      testVectorConnection,
      testVectorCluster,
      isPaperInVectorStore
    };
  }
};
